import{_ as a,o as t,c as r,a3 as d}from"./chunks/framework.oxq6d-og.js";const u=JSON.parse('{"title":"NThread sorun giderme","description":"","frontmatter":{},"headers":[],"relativePath":"nthread/troubleshooting.md","filePath":"nthread/troubleshooting.md"}'),i={name:"nthread/troubleshooting.md"};function n(o,e,l,s,m,c){return t(),r("div",null,[...e[0]||(e[0]=[d('<h1 id="nthread-sorun-giderme" tabindex="-1">NThread sorun giderme <a class="header-anchor" href="#nthread-sorun-giderme" aria-label="Permalink to &quot;NThread sorun giderme&quot;">​</a></h1><p>Bu sayfa hata mesajını belirti olarak ele alır. Amaç, hemen daha büyük timeout vermek değil, çağrının hangi aşamada bozulduğunu ayırmaktır.</p><table tabindex="0"><thead><tr><th>Belirti</th><th>Muhtemel neden</th><th>İlk kontrol</th></tr></thead><tbody><tr><td><code>No*AddressError</code></td><td>Stub taraması tamamlanmadı veya uygun stub bulunamadı</td><td>Windows x64, modül erişimi ve init sırası</td></tr><tr><td><code>CallTimeoutError</code></td><td>Fonksiyon dönmedi, yanlış ABI, thread kilitlendi</td><td>Hedef adresi, imza, thread durumu, timeout</td></tr><tr><td><code>CallThreadDiedError</code></td><td>Thread sonlandı veya çağrı akışı thread&#39;i bitirdi</td><td>Exit code, çağrılan fonksiyonun dönüş davranışı</td></tr><tr><td>RSP mismatch uyarısı</td><td>Return chain veya stack argümanı hatası</td><td>Argüman sayısı, shadow space, hizalama</td></tr><tr><td>Hook enable timeout</td><td>Driving thread yanlışlıkla ayrıca suspend edildi</td><td>NThread/accessor thread ID&#39;si</td></tr><tr><td>Hedef donuyor</td><td>Park edilen thread lock veya UI döngüsü taşıyor</td><td>Thread seçimi ve lock sahipliği</td></tr></tbody></table><h2 id="stub-hataları" tabindex="-1">Stub hataları <a class="header-anchor" href="#stub-hataları" aria-label="Permalink to &quot;Stub hataları&quot;">​</a></h2><p>NThread, <code>ntdll</code>, <code>kernel32</code> ve <code>kernelbase</code> içinde <code>EB FE</code>, <code>push reg; ret</code>, <code>jmp reg</code>, <code>ret</code> ve <code>add rsp, 0x28; ret</code> arar. Async başlatma bu taramanın bitmesini bekler. Hata devam ederse “başka bir stub adresi uydurmak” yerine platform, mimari ve modül haritalamasını kontrol edin.</p><h2 id="timeout" tabindex="-1">Timeout <a class="header-anchor" href="#timeout" aria-label="Permalink to &quot;Timeout&quot;">​</a></h2><p>Timeout, hedef fonksiyonun hatalı olduğu anlamına gelmez; thread&#39;in spin stub&#39;a dönmediği anlamına gelir. Önce çağrıyı mümkünse yerelde veya normal bir remote accessor ile doğrulayın. Ardından argümansız, hızlı bir Win32 fonksiyonuyla NThread zincirini izole edin. Sadece timeout değerini artırmak, deadlock&#39;u uzun süre gizleyebilir.</p><h2 id="stack-mismatch" tabindex="-1">Stack mismatch <a class="header-anchor" href="#stack-mismatch" aria-label="Permalink to &quot;Stack mismatch&quot;">​</a></h2><p>NThread, <code>expectedRsp</code> ayarlanmışsa hem <code>call()</code> hem <code>callSync()</code> sonrasında <code>RSP</code> denetimi yapar. Uyumsuzluk gördüğünüzde önce beşinci ve sonraki argümanları inceleyin. Bu çağrılar, stack slotlarını ve dinamik <code>add rsp, 0x28 + N*8; ret</code> stub&#39;ını kullanır. Bir imza hatası, fonksiyonun kendi stack cleanup&#39;ını bozmuş gibi görünebilir.</p><h2 id="minimum-yeniden-uretim" tabindex="-1">Minimum yeniden üretim <a class="header-anchor" href="#minimum-yeniden-uretim" aria-label="Permalink to &quot;Minimum yeniden üretim&quot;">​</a></h2><ol><li>Yeni başlatılmış, kendi kontrolünüzde bir hedef süreç kullanın.</li><li>Tek thread veya gözlemlenebilir bir race kazananı seçin.</li><li>Önce yan etkisiz ve hızlı çağrıyla accessor&#39;ı doğrulayın.</li><li>Bir seferde yalnızca adres, argüman türü veya hook türü gibi tek değişkeni değiştirin.</li><li>Çökme varsa yeni süreç örneğiyle devam edin; bozulmuş context&#39;i tekrar kullanmayın.</li></ol>',11)])])}const k=a(i,[["render",n]]);export{u as __pageData,k as default};
